import{_ as s,c as t,o as i,a1 as e}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"代码审查工作流：建立早期审查习惯，掌握请求和接收代码审查的最佳实践方法 | Superpowers 教程","description":"学习如何使用 Superpowers 的代码审查工作流，在每个开发阶段主动请求审查并处理反馈。教程涵盖请求审查、区分反馈优先级、技术性验证反馈、避免表演性同意等最佳实践，帮助你建立早期、频繁的审查习惯，保持代码质量基线，减少后期返工成本。","frontmatter":{"title":"代码审查工作流：建立早期审查习惯，掌握请求和接收代码审查的最佳实践方法 | Superpowers 教程","sidebarTitle":"建立审查习惯","subtitle":"代码审查工作流：建立有效的审查习惯","description":"学习如何使用 Superpowers 的代码审查工作流，在每个开发阶段主动请求审查并处理反馈。教程涵盖请求审查、区分反馈优先级、技术性验证反馈、避免表演性同意等最佳实践，帮助你建立早期、频繁的审查习惯，保持代码质量基线，减少后期返工成本。","tags":["高级","代码审查","工作流"],"prerequisite":["start-using-skills","advanced-subagent-development"],"order":160},"headers":[],"relativePath":"zh/obra/superpowers/advanced/code-review-workflow/index.md","filePath":"zh/obra/superpowers/advanced/code-review-workflow/index.md"}'),n={name:"zh/obra/superpowers/advanced/code-review-workflow/index.md"};function l(r,a,p,o,d,h){return i(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="代码审查工作流-建立有效的审查习惯" tabindex="-1">代码审查工作流：建立有效的审查习惯 <a class="header-anchor" href="#代码审查工作流-建立有效的审查习惯" aria-label="Permalink to &quot;代码审查工作流：建立有效的审查习惯&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>在每个开发阶段主动请求代码审查</li><li>正确处理审查反馈，区分 Critical、Important、Minor 优先级</li><li>接收反馈时进行技术性验证，避免表演性同意</li><li>建立早期、频繁的审查习惯</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>AI 代理在开发时容易陷入这些问题：</p><ul><li>完成任务后直接进入下一步，没有审查环节</li><li>收到反馈后盲目实现，不验证技术正确性</li><li>审查流于形式，无法发现实际问题</li><li>认为&quot;代码很简单&quot;就跳过审查</li></ul><p>这些问题会导致：</p><ul><li>小问题累积成大问题</li><li>低质量代码进入主分支</li><li>技术债不断积累</li><li>后期维护成本高昂</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><strong>Review early, review often</strong> —— 早期审查，经常审查。</p><p>代码审查不是开发完成后的&quot;过场&quot;，而是开发流程中的核心环节。通过持续审查，你可以：</p><ul><li>在问题变复杂前发现它们</li><li>保持代码质量基线</li><li>学习更好的编码实践</li><li>减少后期返工</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p><strong>必须审查</strong>：</p><ul><li>每个子代理任务完成后</li><li>完成主要功能后</li><li>合并到 main 分支前</li></ul><p><strong>建议审查</strong>：</p><ul><li>卡住时（需要新视角）</li><li>重构前（建立基线）</li><li>修复复杂 bug 后</li></ul><div class="warning custom-block"><p class="custom-block-title">禁止跳过审查</p><p>即使代码看起来很简单，也不能跳过审查。&quot;简单&quot;代码往往藏着不易发现的 bug 或设计问题。</p></div><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><p>确保已：</p><ol><li>完成 <a href="./../subagent-development/">子代理驱动开发</a> 教程</li><li>熟悉基础 Git 操作（获取 SHA、查看提交）</li><li>已在当前分支完成至少一个开发任务</li></ol><h2 id="跟我做-请求代码审查" tabindex="-1">跟我做：请求代码审查 <a class="header-anchor" href="#跟我做-请求代码审查" aria-label="Permalink to &quot;跟我做：请求代码审查&quot;">​</a></h2><h3 id="第-1-步-获取提交范围" tabindex="-1">第 1 步：获取提交范围 <a class="header-anchor" href="#第-1-步-获取提交范围" aria-label="Permalink to &quot;第 1 步：获取提交范围&quot;">​</a></h3><p><strong>为什么</strong> 需要告诉审查者从哪个提交开始看，到哪个提交结束。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 获取上一个提交的 SHA</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">BASE_SHA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD~1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或者对比 origin/main</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">BASE_SHA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin/main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 获取当前提交的 SHA</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HEAD_SHA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li><code>BASE_SHA</code> 变量包含起始提交的完整 SHA</li><li><code>HEAD_SHA</code> 变量包含结束提交的完整 SHA</li></ul><h3 id="第-2-步-调用-code-reviewer-子代理" tabindex="-1">第 2 步：调用 code-reviewer 子代理 <a class="header-anchor" href="#第-2-步-调用-code-reviewer-子代理" aria-label="Permalink to &quot;第 2 步：调用 code-reviewer 子代理&quot;">​</a></h3><p><strong>为什么</strong> code-reviewer 是专门的审查代理，会系统性检查代码质量、架构和测试覆盖率。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用 Task tool 调用 code-reviewer 子代理</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">@code-reviewer</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 填写模板中的占位符：</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> WHAT_WAS_IMPLEMENTED:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 刚刚实现了什么功能</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PLAN_OR_REQUIREMENTS:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 应该实现什么（引用计划文档或需求）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> BASE_SHA:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 起始提交</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SHA</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD_SHA:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 结束提交</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SHA</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DESCRIPTION:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 简要描述改动</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">code-reviewer 子代理</p><p>code-reviewer 子代理定义在 <code>agents/code-reviewer.md</code>，它会从以下维度审查代码：</p><ol><li>计划一致性</li><li>代码质量</li><li>架构设计</li><li>文档规范</li><li>安全性和性能</li></ol></div><p><strong>你应该看到</strong>：</p><ul><li>子代理返回结构化的审查报告</li><li>报告包含：Strengths（优点）、Issues（问题）、Assessment（评估）</li></ul><h3 id="第-3-步-处理审查反馈" tabindex="-1">第 3 步：处理审查反馈 <a class="header-anchor" href="#第-3-步-处理审查反馈" aria-label="Permalink to &quot;第 3 步：处理审查反馈&quot;">​</a></h3><p><strong>为什么</strong> 反馈分级帮助你确定优先级，合理分配修复时间。</p><table tabindex="0"><thead><tr><th>优先级</th><th>含义</th><th>处理方式</th></tr></thead><tbody><tr><td>Critical</td><td>必须修复</td><td>立即修复，否则无法继续</td></tr><tr><td>Important</td><td>应该修复</td><td>在继续下一步前修复</td></tr><tr><td>Minor</td><td>建议优化</td><td>记录下来，稍后处理</td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 示例：处理 feedback</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 修复 Critical 问题</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Fixing Critical issue: missing error handling&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 修复 Important 问题</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Fixing Important issue: add progress indicators&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 记录 Minor 问题</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Minor issue: magic number (100) - defer to later&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. 如果审查者判断错误，用技术理由推回</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Reviewer suggested removing legacy code, but we need it for backward compat. Keeping with note.&quot;</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li>Critical 和 Important 问题已修复</li><li>Minor 问题已记录</li><li>有技术支撑的推回理由（如有）</li></ul><h3 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h3><ul><li>[ ] 已获取 <code>BASE_SHA</code> 和 <code>HEAD_SHA</code></li><li>[ ] 已调用 code-reviewer 子代理</li><li>[ ] 已修复所有 Critical 问题</li><li>[ ] 已修复或计划修复 Important 问题</li><li>[ ] Minor 问题已记录</li></ul><h2 id="接收反馈的技术原则" tabindex="-1">接收反馈的技术原则 <a class="header-anchor" href="#接收反馈的技术原则" aria-label="Permalink to &quot;接收反馈的技术原则&quot;">​</a></h2><p><strong>核心原则</strong>：Verify before implementing, ask before assuming.</p><h3 id="响应模式" tabindex="-1">响应模式 <a class="header-anchor" href="#响应模式" aria-label="Permalink to &quot;响应模式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当收到代码审查反馈时：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. READ: 完整阅读反馈，不要立即反应</span></span>
<span class="line"><span>2. UNDERSTAND: 用自己的话重述需求（或提问）</span></span>
<span class="line"><span>3. VERIFY: 对照代码库实际情况验证</span></span>
<span class="line"><span>4. EVALUATE: 技术上是否适合当前代码库？</span></span>
<span class="line"><span>5. RESPOND: 技术性确认或推回理由</span></span>
<span class="line"><span>6. IMPLEMENT: 逐项实现，每项都测试</span></span></code></pre></div><h3 id="禁止的响应方式" tabindex="-1">禁止的响应方式 <a class="header-anchor" href="#禁止的响应方式" aria-label="Permalink to &quot;禁止的响应方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>❌ 禁止</th><th>✅ 正确</th></tr></thead><tbody><tr><td>&quot;You&#39;re absolutely right!&quot;（违反 CLAUDE.md）</td><td>&quot;Checking codebase...&quot;</td></tr><tr><td>&quot;Great point!&quot; / &quot;Excellent feedback!&quot;（表演性）</td><td>&quot;I understand this to mean...&quot;</td></tr><tr><td>&quot;Let me implement that now&quot;（验证前）</td><td>&quot;Before implementing, let me verify...&quot;</td></tr></tbody></table><h3 id="处理不清晰的反馈" tabindex="-1">处理不清晰的反馈 <a class="header-anchor" href="#处理不清晰的反馈" aria-label="Permalink to &quot;处理不清晰的反馈&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">遇到不清晰的反馈</p><p>如果审查反馈中有任何项目不清晰，<strong>停止</strong>，不要实现任何内容，先请求澄清。</p><p>为什么：反馈项目可能相互关联。部分理解 = 错误实现。</p></div><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的搭档说：&quot;Fix items 1-6&quot;</span></span>
<span class="line"><span>你理解 1、2、3、6，但不清楚 4、5。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❌ 错误：现在实现 1、2、3、6，稍后问 4、5</span></span>
<span class="line"><span>✅ 正确：&quot;我理解项目 1、2、3、6。需要先澄清 4 和 5 才能继续。&quot;</span></span></code></pre></div><h3 id="处理外部审查者的反馈" tabindex="-1">处理外部审查者的反馈 <a class="header-anchor" href="#处理外部审查者的反馈" aria-label="Permalink to &quot;处理外部审查者的反馈&quot;">​</a></h3><p>外部审查者的建议需要额外验证：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实现前检查：</span></span>
<span class="line"><span>1. 技术上是否正确？</span></span>
<span class="line"><span>2. 是否破坏现有功能？</span></span>
<span class="line"><span>3. 是否了解当前实现的原因？</span></span>
<span class="line"><span>4. 是否在所有平台/版本上都适用？</span></span>
<span class="line"><span>5. 审查者是否了解完整上下文？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果建议看起来不对：</span></span>
<span class="line"><span>→ 用技术理由推回</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果无法轻松验证：</span></span>
<span class="line"><span>→ 说明：&quot;如果没有 [X]，我无法验证。我应该 [调查/询问/继续] 吗？&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果与你的搭档之前的决策冲突：</span></span>
<span class="line"><span>→ 停止，先与你的搭档讨论</span></span></code></pre></div><h3 id="yagni-检查" tabindex="-1">YAGNI 检查 <a class="header-anchor" href="#yagni-检查" aria-label="Permalink to &quot;YAGNI 检查&quot;">​</a></h3><p>当审查者建议&quot;正确实现&quot;某个功能时：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 检查代码库中是否有实际使用</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;functionName&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 如果没有使用</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;这个端点没有被调用。删除它（YAGNI）？&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 如果有使用</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;好的，正确实现这个功能。&quot;</span></span></code></pre></div><p><strong>你的搭档的规则</strong>：&quot;你和审查者都向我汇报。如果我们不需要这个功能，就不要添加它。&quot;</p><h3 id="实现顺序" tabindex="-1">实现顺序 <a class="header-anchor" href="#实现顺序" aria-label="Permalink to &quot;实现顺序&quot;">​</a></h3><p>处理多项目反馈时：</p><ol><li><strong>先</strong>澄清任何不清晰的项目</li><li><strong>然后</strong>按以下顺序实现： <ul><li>阻塞性问题（破坏性、安全性）</li><li>简单修复（拼写、导入）</li><li>复杂修复（重构、逻辑）</li></ul></li><li>逐项测试每个修复</li><li>验证没有回归</li></ol><h3 id="什么时候应该推回" tabindex="-1">什么时候应该推回 <a class="header-anchor" href="#什么时候应该推回" aria-label="Permalink to &quot;什么时候应该推回&quot;">​</a></h3><p><strong>推回场景</strong>：</p><ul><li>建议破坏现有功能</li><li>审查者缺乏完整上下文</li><li>违反 YAGNI（未使用的功能）</li><li>对当前技术栈技术不正确</li><li>存在遗留/兼容性原因</li><li>与你的搭档的架构决策冲突</li></ul><p><strong>如何推回</strong>：</p><ul><li>使用技术理由，而不是防御性态度</li><li>提出具体问题</li><li>引用可工作的测试/代码</li><li>如果涉及架构问题，让你的搭档参与</li></ul><p><strong>信号</strong>：如果你对公开推回感到不适，说：&quot;Strange things are afoot at the Circle K&quot;</p><h3 id="确认正确的反馈" tabindex="-1">确认正确的反馈 <a class="header-anchor" href="#确认正确的反馈" aria-label="Permalink to &quot;确认正确的反馈&quot;">​</a></h3><p>当反馈是正确的时候：</p><table tabindex="0"><thead><tr><th>✅ 正确</th><th>❌ 错误</th></tr></thead><tbody><tr><td>&quot;Fixed. [简短描述改变的内容]&quot;</td><td>&quot;You&#39;re absolutely right!&quot;</td></tr><tr><td>&quot;Good catch - [具体问题]. 在 [位置] 修复了。&quot;</td><td>&quot;Great point!&quot;</td></tr><tr><td>[直接修复并在代码中展示]</td><td>&quot;Thanks for catching that!&quot;</td></tr><tr><td></td><td>&quot;Thanks for [任何内容]&quot;</td></tr><tr><td></td><td>任何感谢表达</td></tr></tbody></table><p><strong>为什么不感谢</strong>：行动胜于言辞。直接修复它。代码本身表明你听到了反馈。</p><p><strong>如果你发现自己想写&quot;Thanks&quot;</strong>：删除它。改写修复说明。</p><h3 id="优雅地纠正你的推回" tabindex="-1">优雅地纠正你的推回 <a class="header-anchor" href="#优雅地纠正你的推回" aria-label="Permalink to &quot;优雅地纠正你的推回&quot;">​</a></h3><p>如果你推回了但结果是错的：</p><table tabindex="0"><thead><tr><th>✅ 正确</th><th>❌ 错误</th></tr></thead><tbody><tr><td>&quot;你是对的——我检查了 [X]，它确实 [Y]。正在实现。&quot;</td><td>长篇道歉</td></tr><tr><td>&quot;验证了这一点，你是正确的。我最初的理解是错的，因为 [原因]。正在修复。&quot;</td><td>为为什么推回而辩护</td></tr><tr><td></td><td>过度解释</td></tr></tbody></table><p>如实地陈述纠正并继续。</p><h3 id="github-线程回复" tabindex="-1">GitHub 线程回复 <a class="header-anchor" href="#github-线程回复" aria-label="Permalink to &quot;GitHub 线程回复&quot;">​</a></h3><p>在 GitHub 上回复内联审查评论时，在评论线程中回复（<code>gh api repos/{owner}/{repo}/pulls/{pr}/comments/{id}/replies</code>），而不是作为顶级 PR 评论。</p><h3 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h3><table tabindex="0"><thead><tr><th>错误</th><th>修正</th></tr></thead><tbody><tr><td>表演性同意</td><td>陈述要求或直接行动</td></tr><tr><td>盲目实现</td><td>先对照代码库验证</td></tr><tr><td>批量不测试</td><td>逐项实现，每项测试</td></tr><tr><td>假设审查者是对的</td><td>检查是否破坏东西</td></tr><tr><td>避免推回</td><td>技术正确性 &gt; 舒适度</td></tr><tr><td>部分实现</td><td>先澄清所有项目</td></tr><tr><td>无法验证，但继续进行</td><td>说明限制，询问方向</td></tr></tbody></table><h3 id="真实示例" tabindex="-1">真实示例 <a class="header-anchor" href="#真实示例" aria-label="Permalink to &quot;真实示例&quot;">​</a></h3><p><strong>表演性同意（不好）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>审查者：&quot;Remove legacy code&quot;</span></span>
<span class="line"><span>❌ &quot;You&#39;re absolutely right! Let me remove that...&quot;</span></span></code></pre></div><p><strong>技术验证（好）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>审查者：&quot;Remove legacy code&quot;</span></span>
<span class="line"><span>✅ &quot;Checking... build target is 10.15+, this API needs 13+. Need legacy for backward compat. Current impl has wrong bundle ID - fix it or drop pre-13 support?&quot;</span></span></code></pre></div><p><strong>YAGNI（好）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>审查者：&quot;Implement proper metrics tracking with database, date filters, CSV export&quot;</span></span>
<span class="line"><span>✅ &quot;Grepped codebase - nothing calls this endpoint. Remove it (YAGNI)? Or is there usage I&#39;m missing?&quot;</span></span></code></pre></div><p><strong>不清楚的项目（好）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的搭档：&quot;Fix items 1-6&quot;</span></span>
<span class="line"><span>你理解 1、2、3、6，不清楚 4、5。</span></span>
<span class="line"><span>✅ &quot;Understand 1,2,3,6. Need clarification on 4 and 5 before implementing.&quot;</span></span></code></pre></div><h2 id="底线" tabindex="-1">底线 <a class="header-anchor" href="#底线" aria-label="Permalink to &quot;底线&quot;">​</a></h2><p><strong>外部反馈 = 要评估的建议，不是要遵循的命令。</strong></p><p>验证。提问。然后实现。</p><p>禁止表演性同意。始终技术严谨。</p><h2 id="与其他工作流集成" tabindex="-1">与其他工作流集成 <a class="header-anchor" href="#与其他工作流集成" aria-label="Permalink to &quot;与其他工作流集成&quot;">​</a></h2><h3 id="子代理驱动开发" tabindex="-1">子代理驱动开发 <a class="header-anchor" href="#子代理驱动开发" aria-label="Permalink to &quot;子代理驱动开发&quot;">​</a></h3><ul><li><strong>每个任务后</strong>审查</li><li>在问题复合之前发现它们</li><li>在继续下一个任务之前修复</li></ul><h3 id="执行计划" tabindex="-1">执行计划 <a class="header-anchor" href="#执行计划" aria-label="Permalink to &quot;执行计划&quot;">​</a></h3><ul><li>**每批任务后（3 个任务）**审查</li><li>获取反馈，应用反馈，继续</li></ul><h3 id="临时开发" tabindex="-1">临时开发 <a class="header-anchor" href="#临时开发" aria-label="Permalink to &quot;临时开发&quot;">​</a></h3><ul><li>合并前审查</li><li>卡住时审查</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><table tabindex="0"><thead><tr><th>错误</th><th>后果</th><th>预防方法</th></tr></thead><tbody><tr><td>认为&quot;代码很简单&quot;就跳过审查</td><td>隐藏的 bug 进入主分支</td><td>即使是 10 行代码也要审查</td></tr><tr><td>盲目实现审查建议</td><td>引入新问题或破坏现有功能</td><td>实现前对照代码库验证</td></tr><tr><td>逐项修复但不测试</td><td>回归 bug</td><td>每项修复后立即测试</td></tr><tr><td>对错误的建议表演性同意</td><td>低质量代码累积</td><td>技术正确性 &gt; 社交舒适度</td></tr><tr><td>部分理解就实现</td><td>错误实现</td><td>不清楚的项目先请求澄清</td></tr></tbody></table><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>代码审查工作流的核心是：</p><ul><li><strong>Review early, review often</strong> —— 早期、频繁审查</li><li><strong>技术验证优先</strong> —— Verify before implementing</li><li><strong>分级处理反馈</strong> —— Critical/Important/Minor</li><li><strong>禁止表演性同意</strong> —— 技术正确性 &gt; 社交舒适度</li></ul><p>通过建立有效的审查习惯，你可以：</p><ul><li>在问题变复杂前发现它们</li><li>保持代码质量基线</li><li>学习更好的编码实践</li><li>减少后期返工成本</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../git-worktrees/">Git 工作树隔离</a></strong>。</p><p>你会学到：</p><ul><li>使用 Git 工作树创建隔离的开发环境</li><li>在多个功能之间同时工作而不干扰</li><li>保持主分支的清洁和稳定</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>请求代码审查技能</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/requesting-code-review/SKILL.md" target="_blank" rel="noreferrer"><code>skills/requesting-code-review/SKILL.md</code></a></td><td>1-106</td></tr><tr><td>接收代码审查技能</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/receiving-code-review/SKILL.md" target="_blank" rel="noreferrer"><code>skills/receiving-code-review/SKILL.md</code></a></td><td>1-214</td></tr><tr><td>code-reviewer 代理定义</td><td><a href="https://github.com/obra/superpowers/blob/main/agents/code-reviewer.md" target="_blank" rel="noreferrer"><code>agents/code-reviewer.md</code></a></td><td>1-49</td></tr></tbody></table><p><strong>关键原则</strong>：</p><ul><li><strong>Review early, review often</strong>：早期、频繁审查（<code>requesting-code-review/SKILL.md:10</code>）</li><li><strong>Verify before implementing</strong>：实现前验证（<code>receiving-code-review/SKILL.md:12</code>）</li><li><strong>Technical correctness &gt; social comfort</strong>：技术正确性 &gt; 社交舒适度（<code>receiving-code-review/SKILL.md:12</code>）</li></ul><p><strong>反馈分级</strong>（<code>agents/code-reviewer.md:37</code>）：</p><ul><li>Critical（必须修复）</li><li>Important（应该修复）</li><li>Suggestions（建议优化）</li></ul><p><strong>禁止的响应</strong>（<code>receiving-code-review/SKILL.md:29-32</code>）：</p><ul><li>&quot;You&#39;re absolutely right!&quot;</li><li>&quot;Great point!&quot;</li><li>&quot;Let me implement that now&quot;</li></ul></details>`,112)])])}const k=s(n,[["render",l]]);export{u as __pageData,k as default};
